#!/usr/bin/env node
/**
 * m6.1 T1b — generate scripts/ant-cli-version-constant.mjs from package.json
 * BEFORE `bun build --compile`. The compiled single-binary can't read the
 * outer package.json (relative paths break post-compile), so the version
 * must be inlined as a constant that bun bundles into the binary.
 *
 * Pipeline: npm run prebuild:cli  (generates constant)  →  bun build --compile
 * The generated file is .gitignored so it doesn't drift from package.json.
 */
import { readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const pkgPath = join(here, '..', 'package.json');
const outPath = join(here, 'ant-cli-version-constant.mjs');
const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
const version = typeof pkg.version === 'string' && pkg.version.length > 0 ? pkg.version : '0.0.0';

const body = `// AUTO-GENERATED by scripts/build-cli-version-constant.mjs — DO NOT EDIT.
// Regenerated from package.json before each \`bun build --compile\`.
export const ANT_CLI_VERSION_CONSTANT = ${JSON.stringify(version)};
`;
writeFileSync(outPath, body, 'utf8');
console.log(`wrote ${outPath} (ANT_CLI_VERSION_CONSTANT = ${JSON.stringify(version)})`);
